<!-- RÉSUMÉ PAR VILLE -->
<div class="city-grid">
  ${villes.map(v => v.error ? `<div class="city-card"><h3>${escHtml(v.ville)}</h3><div style="color:#dc2626;font-size:12px;">Erreur: ${escHtml(v.error)}</div></div>` : `<div class="city-card">
